// api/admin/seed_poi_lacedonia_completo.php
// Seed completo POI Lacedonia — testi IT+EN, identità, categorie.
// Usa ON DUPLICATE KEY UPDATE: idempotente, aggiorna i record esistenti.
require_once __DIR__ . '/../config/db.php';
requireAdminSession();
$db = getDB();
$results = []; $errors = [];

function upsertPoi(PDO $db, array $d, array &$results, array &$errors): void {
    try {
        $db->prepare("
            INSERT INTO points_of_interest
                (id, borough_id, category, sort_order,
                 name_it, name_en,
                 desc_it, desc_en,
                 tags)
            VALUES
                (:id, :borough_id, :category, :sort_order,
                 :name_it, :name_en,
                 :desc_it, :desc_en,
                 :tags)
            ON DUPLICATE KEY UPDATE
                category   = VALUES(category),
                sort_order = VALUES(sort_order),
                name_it    = VALUES(name_it),
                name_en    = VALUES(name_en),
                desc_it    = VALUES(desc_it),
                desc_en    = VALUES(desc_en),
                tags       = VALUES(tags)
        ")->execute($d);
        $results[] = '✅ ' . $d['name_it'];
    } catch (PDOException $e) {
        $errors[] = '❌ ' . ($d['name_it'] ?? $d['id']) . ': ' . $e->getMessage();
    }
}

